	public static void recordGlobalCardinalityObservation(String source, double estimated, double actual) {
		if (source == null || source.isBlank()) {
			return;
		}
		if (!isCalibrationEnabled()) {
			return;
		}
		ensureCalibrationPersistenceLoaded();
		double qError = computeQError(estimated, actual);
		if (!Double.isFinite(qError) || qError < 1.0) {
			return;
		}
		double alpha = readCalibrationAlpha();
		CALIBRATION_STATES.computeIfAbsent(source, key -> new CalibrationState()).observe(qError, alpha);
		enforceCalibrationSourceLimit();
		markCalibrationPersistenceDirty();
		persistCalibrationStates(false);
	}

