	private static double sanitizeCardinality(double value) {
		if (Double.isNaN(value) || value < 0.0) {
			return 0.0;
		}
		if (Double.isInfinite(value)) {
			return Double.MAX_VALUE;
		}
		return value;
	}

	private static double sanitizeConfidence(double value) {
		if (Double.isNaN(value)) {
			return 0.0;
		}
		if (value < 0.0) {
			return 0.0;
		}
		if (value > 1.0) {
			return 1.0;
		}
		return value;
	}

	private CardinalityEstimate applyCalibration(CardinalityEstimate estimate) {
		if (!isCalibrationEnabled()) {
			return estimate;
		}
		CalibrationSnapshot snapshot = getCalibrationSnapshot(estimate.source);
		if (snapshot == null || snapshot.sampleCount <= 0) {
			return estimate;
		}

		double calibratedQError = Math.max(1.0, snapshot.ewmaQError);
		double calibratedLowerBound = Math.min(estimate.lowerBound, estimate.estimate / calibratedQError);
		double calibratedUpperBound = Math.max(estimate.upperBound, estimate.estimate * calibratedQError);
		double calibratedConfidence = estimate.confidence * snapshot.confidenceScale;

		return new CardinalityEstimate(estimate.estimate, calibratedLowerBound, calibratedUpperBound,
				calibratedConfidence, estimate.source);
	}

	private static double computeQError(double estimated, double actual) {
		double sanitizedEstimated = sanitizeCardinality(estimated);
		double sanitizedActual = sanitizeCardinality(actual);
		if (sanitizedEstimated == 0.0 && sanitizedActual == 0.0) {
			return 1.0;
		}
		if (sanitizedEstimated == 0.0 || sanitizedActual == 0.0) {
			return Double.POSITIVE_INFINITY;
		}
		return Math.max(sanitizedEstimated / sanitizedActual, sanitizedActual / sanitizedEstimated);
	}

	private static double readCalibrationAlpha() {
		String configured = System.getProperty(CALIBRATION_ALPHA_PROPERTY);
		if (configured == null || configured.isBlank()) {
			return DEFAULT_CALIBRATION_ALPHA;
		}
		try {
			double parsed = Double.parseDouble(configured.trim());
			if (parsed > 0.0 && parsed <= 1.0) {
				return parsed;
			}
		} catch (NumberFormatException ignored) {
			// fall back to default
		}
		return DEFAULT_CALIBRATION_ALPHA;
	}

